import React, { useState } from 'react';
import { useSpring, animated, config } from '@react-spring/web';
import { 
  BoltIcon, 
  ChevronUpIcon, 
  XMarkIcon,
  MagnifyingGlassIcon,
  PaperAirplaneIcon,
  PaperClipIcon,
  LinkIcon
} from '@heroicons/react/24/outline';

const AnimatedBottomSheet = ({ 
  activeTab, 
  setActiveTab, 
  selectedUsers, 
  message, 
  setMessage, 
  teamMembers, 
  toggleUserSelection, 
  removeSelectedUser 
}) => {
  const [isOpen, setIsOpen] = useState(false);

  // Animação principal do container
  const containerAnimation = useSpring({
    width: isOpen ? '400px' : '300px',
    height: isOpen ? '600px' : '60px',
    borderRadius: isOpen ? '16px 16px 0px 0px' : '16px 16px 0px 0px',
    config: config.gentle,
  });

  // Animação do conteúdo
  const contentAnimation = useSpring({
    opacity: isOpen ? 1 : 0,
    transform: isOpen ? 'translateY(0px)' : 'translateY(20px)',
    config: config.gentle,
    delay: isOpen ? 150 : 0,
  });

  // Animação do header fechado
  const closedHeaderAnimation = useSpring({
    opacity: isOpen ? 0 : 1,
    transform: isOpen ? 'translateY(-10px)' : 'translateY(0px)',
    config: config.gentle,
    delay: isOpen ? 0 : 150,
  });

  const toggleSheet = () => {
    setIsOpen(!isOpen);
  };

  return (
    <div className="fixed bottom-0 left-1/2 transform -translate-x-1/2 z-50">
      <animated.div
        style={containerAnimation}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl overflow-hidden"
      >
        {/* Header Fechado */}
        <animated.div
          style={closedHeaderAnimation}
          className={`${isOpen ? 'pointer-events-none' : 'pointer-events-auto'}`}
        >
          <button
            onClick={toggleSheet}
            className="flex items-center justify-between w-full bg-neutral-900 hover:bg-neutral-800 text-white px-4 py-3 transition-colors"
          >
            {/* Left side - Bolt icon with badge */}
            <div className="flex items-center space-x-3">
              <div className="relative">
                <div className="bg-neutral-800 p-2 rounded-full">
                  <BoltIcon className="h-5 w-5 text-white" />
                </div>
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  1
                </span>
              </div>
              <span className="text-white font-medium">Nudges</span>
            </div>

            {/* Right side - Action icons */}
            <div className="flex items-center space-x-2">
              <ChevronUpIcon className="h-5 w-5 text-gray-400 hover:text-white transition-colors" />
            </div>
          </button>
        </animated.div>

        {/* Conteúdo Aberto */}
        <animated.div
          style={contentAnimation}
          className={`${isOpen ? 'pointer-events-auto' : 'pointer-events-none'} p-4`}
        >
          {/* Header Aberto */}
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center space-x-3">
              <div className="relative">
                <div className="w-10 h-10 bg-neutral-900 border border-neutral-700 rounded-full flex items-center justify-center">
                  <BoltIcon className="h-6 w-6 text-white" />
                </div>
                <div className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full flex items-center justify-center">
                  <span className="text-xs font-bold text-white">1</span>
                </div>
              </div>
              <h2 className="text-lg font-semibold text-white">Nudges</h2>
            </div>
            <button
              onClick={toggleSheet}
              className="text-gray-400 hover:text-white transition-colors"
            >
              <XMarkIcon className="h-6 w-6" />
            </button>
          </div>

          {/* Tabs */}
          <div className="flex space-x-2 bg-neutral-900 p-2 rounded-lg mb-4">
            <button
              onClick={() => setActiveTab('send')}
              className={`flex-1 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                activeTab === 'send'
                  ? 'bg-neutral-700 text-white'
                  : 'bg-transparent text-gray-400 hover:text-gray-300'
              }`}
            >
              Send
            </button>
            <button
              onClick={() => setActiveTab('received')}
              className={`flex-1 px-4 py-2 rounded-lg text-sm font-medium transition-colors relative ${
                activeTab === 'received'
                  ? 'bg-neutral-700 text-white'
                  : 'bg-transparent text-gray-400 hover:text-gray-300'
              }`}
            >
              Received
              <span className="ml-2 text-xs text-gray-500">1</span>
            </button>
          </div>

          {/* Search */}
          <div className="relative mb-4">
            <input
              type="text"
              placeholder="Search for team member..."
              className="w-full bg-transparent border border-neutral-700 rounded-lg px-4 py-3 pr-10 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
            <MagnifyingGlassIcon className="absolute right-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
          </div>

          {/* Selected Users */}
          {selectedUsers.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-4">
              {selectedUsers.map((user) => (
                <div
                  key={user.id}
                  className="flex items-center space-x-2 bg-neutral-700 rounded-lg px-3 py-2"
                >
                  <img
                    src={user.avatar}
                    alt={user.name}
                    className="w-6 h-6 rounded-full"
                  />
                  <span className="text-white text-sm">{user.name}</span>
                  <button
                    onClick={() => removeSelectedUser(user.id)}
                    className="text-gray-400 hover:text-white"
                  >
                    <XMarkIcon className="h-4 w-4" />
                  </button>
                </div>
              ))}
            </div>
          )}

          {/* Team Members */}
          <div className="grid grid-cols-2 gap-3 mb-4 max-h-32 overflow-y-auto">
            {teamMembers.map((member) => {
              const isSelected = selectedUsers.find(u => u.id === member.id);
              return (
                <button
                  key={member.id}
                  onClick={() => toggleUserSelection(member)}
                  className={`flex items-center space-x-3 p-3 rounded-lg border transition-colors ${
                    isSelected
                      ? 'bg-neutral-700 border-blue-500'
                      : 'bg-neutral-800 border-neutral-600 hover:border-neutral-500'
                  }`}
                >
                  <div className="relative">
                    <img
                      src={member.avatar}
                      alt={member.name}
                      className="w-8 h-8 rounded-full"
                    />
                    <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                      member.status === 'online' ? 'bg-green-500' : 'bg-orange-500'
                    }`} />
                  </div>
                  <span className="text-white text-sm font-medium">{member.name}</span>
                  {isSelected && (
                    <XMarkIcon className="h-4 w-4 text-gray-400 ml-auto" />
                  )}
                </button>
              );
            })}
          </div>

          {/* Message Input */}
          <div className="space-y-3">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Type your message..."
              className="w-full bg-transparent border border-neutral-700 rounded-lg px-4 py-3 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none"
              rows={3}
            />

            {/* Action Buttons */}
            <div className="flex space-x-3">
              <button className="flex items-center justify-center space-x-2 w-1/2 h-9 bg-transparent border border-neutral-700 hover:bg-neutral-700 rounded-lg transition-colors">
                <PaperClipIcon className="h-4 w-4 text-gray-400" />
                <span className="text-gray-300 text-sm">Attach files</span>
              </button>
              <button className="flex items-center justify-center space-x-2 w-1/2 h-9 bg-transparent border border-neutral-700 hover:bg-neutral-700 rounded-lg transition-colors">
                <LinkIcon className="h-4 w-4 text-gray-400" />
                <span className="text-gray-300 text-sm">Add links</span>
              </button>
            </div>

            {/* Send Button */}
            <button
              disabled={!message.trim() || selectedUsers.length === 0}
              className={`w-full h-9 flex items-center justify-center space-x-2 rounded-lg transition-colors ${
                !message.trim() || selectedUsers.length === 0
                  ? 'bg-white bg-opacity-25 cursor-not-allowed'
                  : 'bg-white hover:bg-gray-100'
              }`}
            >
              <PaperAirplaneIcon className={`h-5 w-5 ${
                !message.trim() || selectedUsers.length === 0 ? 'text-gray-400' : 'text-black'
              }`} />
              <span className={`font-medium ${
                !message.trim() || selectedUsers.length === 0 ? 'text-gray-400' : 'text-black'
              }`}>Send Nudge</span>
            </button>
          </div>
        </animated.div>
      </animated.div>
    </div>
  );
};

export default AnimatedBottomSheet;
